// === C++ Timeline: Smooth door open/close ===
// Header
UPROPERTY(VisibleAnywhere)
UTimelineComponent* DoorTimeline;

UPROPERTY(EditAnywhere)
UCurveFloat* DoorCurve; // Set in editor — 0 to 1 over 1 second

FOnTimelineFloat DoorTimelineCallback;
FOnTimelineEvent DoorTimelineFinished;

UFUNCTION()
void DoorTimelineUpdate(float Value);

UFUNCTION()
void DoorTimelineEnd();

bool bIsOpen = false;
FRotator ClosedRotation;
FRotator OpenRotation;

// Source — Constructor
AMyDoor::AMyDoor() {
    DoorTimeline = CreateDefaultSubobject<UTimelineComponent>(TEXT("DoorTimeline"));
}

// Source — BeginPlay
void AMyDoor::BeginPlay() {
    Super::BeginPlay();

    ClosedRotation = DoorMesh->GetRelativeRotation();
    OpenRotation = ClosedRotation + FRotator(0.f, 90.f, 0.f);

    if (DoorCurve) {
        DoorTimelineCallback.BindDynamic(this, &AMyDoor::DoorTimelineUpdate);
        DoorTimelineFinished.BindDynamic(this, &AMyDoor::DoorTimelineEnd);

        DoorTimeline->AddInterpFloat(DoorCurve, DoorTimelineCallback);
        DoorTimeline->SetTimelineFinishedFunc(DoorTimelineFinished);
    }
}

void AMyDoor::ToggleDoor() {
    if (bIsOpen) {
        DoorTimeline->Reverse();
    } else {
        DoorTimeline->Play();
    }
    bIsOpen = !bIsOpen;
}

void AMyDoor::DoorTimelineUpdate(float Value) {
    FRotator NewRot = FMath::Lerp(ClosedRotation, OpenRotation, Value);
    DoorMesh->SetRelativeRotation(NewRot);
}

void AMyDoor::DoorTimelineEnd() {
    // Door finished opening or closing
}

// Blueprint Timeline workflow (described for reference):
//
// 1. In EventGraph, right-click > Add Timeline node > name it 'DoorTimeline'
// 2. Double-click the Timeline node to open the curve editor
// 3. Click '+Float Track' > name it 'Alpha'
// 4. Add two keyframes: (Time=0, Value=0) and (Time=1, Value=1)
// 5. Back in EventGraph:
//    - Connect your trigger (e.g., 'Interact' event) to the 'Play' input
//    - From the 'Update' pin, drag out and use 'Lerp (Rotator)'
//      with A=Closed Rotation, B=Open Rotation, Alpha=the float output
//    - Connect the Lerp result to 'Set Relative Rotation' on your door mesh
//    - From the 'Finished' pin, add any post-animation logic
//
// To reverse (close the door):
//    - Connect a second trigger to the 'Reverse' input
//
// The Timeline handles all the smooth interpolation automatically!
